 23â†’func TestGetSearchFields(t *testing.T) {
 24â†’	t.Parallel()
 25â†’	registry := search.NewRegistry()
 26â†’	handler := makeFieldsHandler(registry)
 27â†’
 28â†’	result, _, err := handler(context.Background(), nil, fieldsInput{})
 29â†’	if err != nil {
 30â†’		t.Fatalf("unexpected error: %v", err)
 31â†’	}
 32â†’	if result == nil {
 33â†’		t.Fatal("result is nil")
 34â†’	}
 35â†’	if len(result.Content) == 0 {
 36â†’		t.Fatal("result has no content")
 37â†’	}
 38â†’
 39â†’	text, ok := result.Content[0].(*mcp.TextContent)
 40â†’	if !ok {
 41â†’		t.Fatalf("expected TextContent, got %T", result.Content[0])
 42â†’	}
 43â†’
 44â†’	var descriptors []search.FieldDescriptor
 45â†’	if err := json.Unmarshal([]byte(text.Text), &descriptors); err != nil {
 46â†’		t.Fatalf("failed to unmarshal descriptors: %v", err)
 47â†’	}
 48â†’	if len(descriptors) == 0 {
 49â†’		t.Error("expected non-empty descriptors list")
 50â†’	}
 51â†’
 52â†’	// Verify that key fields are present.
 53â†’	names := make(map[string]bool)
 54â†’	for _, d := range descriptors {
 55â†’		names[d.Name] = true
 56â†’	}
 57â†’	for _, want := range []string{"name", "state", "enrollment"} {
 58â†’		if !names[want] {
 59â†’			t.Errorf("expected field %q in descriptors", want)
 60â†’		}
 61â†’	}
 62â†’}
