  8â†’// ValidationError describes a single validation failure.
  9â†’type ValidationError struct {
 10â†’	Field   string `json:"field"`
 11â†’	Message string `json:"message"`
 12â†’}
 13â†’
 14â†’// Unexported interfaces let the validator access concrete-type metadata without
 15â†’// widening the public Field interface.
 16â†’type hasEnumOptions interface{ enumOptions() []EnumOption }
 17â†’type hasHardBounds interface{ hardBounds() (min, max *float64) }
 18â†’type hasMaxRadius interface{ maxRadiusKm() float64 }
