143â†’						}
144â†’					}
145â†’				}
146â†’			}
147â†’
148â†’		case KindGeo:
149â†’			var f GeoFilterInput
150â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
151â†’				errs = append(errs, ValidationError{Field: fi.Field,
152â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
153â†’				continue
154â†’			}
155â†’			switch f.Kind {
156â†’			case GeoFilterKindRadius:
157â†’				if f.Radius == nil {
