 97â†’			if hb, ok := field.(hasHardBounds); ok {
 98â†’				hardMin, hardMax := hb.hardBounds()
 99â†’				if f.Min != nil && hardMin != nil && *f.Min < *hardMin {
100â†’					errs = append(errs, ValidationError{Field: fi.Field,
101â†’						Message: "value out of allowed range"})
102â†’				}
103â†’				if f.Max != nil && hardMax != nil && *f.Max > *hardMax {
104â†’					errs = append(errs, ValidationError{Field: fi.Field,
105â†’						Message: "value out of allowed range"})
106â†’				}
107â†’			}
