import { useRef, useEffect } from 'react'
import { print, type DocumentNode } from 'graphql'
import { graphql } from 'gql.tada'

declare global {
  interface Window {
    WebMCP?: new (options: {
      color?: string
      position?: string
      size?: string
      padding?: string
      inactivityTimeout?: number
    }) => WebMCPInstance
  }
}

interface WebMCPInstance {
  registerTool(
    name: string,
    description: string,
    schema: Record<string, unknown>,
    executeFn: (args: Record<string, unknown>) => unknown,
  ): void
}

const SEARCH_FIELDS_QUERY = graphql(`
  query SearchFields {
    searchFields {
      __typename
      name
      label
      description
      visibility
      searchability
      exportable
      ... on ChoiceSearchField {
        options { value displayName }
        minSelections
        maxSelections
      }
    }
  }
`)

const SEARCH_QUERY = graphql(`
  query Search($filters: [FilterInput!], $limit: Int, $offset: Int) {
    search(filters: $filters, limit: $limit, offset: $offset) {
      results {
        unitID
        name
        city
        state
      }
      total
    }
  }
`)

async function gqlFetch(query: DocumentNode, variables?: Record<string, unknown>) {
  const res = await fetch('/graphql', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ query: print(query), variables }),
  })
  const json = await res.json()
  if (json.errors) {
    throw new Error(json.errors.map((e: { message: string }) => e.message).join('; '))
  }
  return json.data
}

export function useWebMCP() {
  const instanceRef = useRef<WebMCPInstance | null>(null)

  useEffect(() => {
    if (instanceRef.current || !window.WebMCP) return

    const mcp = new window.WebMCP({
      color: '#c9a227',
      position: 'bottom-right',
    })
    instanceRef.current = mcp

    mcp.registerTool(
      'search_colleges',
      'Search for colleges using filters like name, state, type, etc. Returns matching institutions.',
      {
        type: 'object',
        properties: {
          filters: {
            type: 'array',
            description: 'Array of filter objects with { field, value } pairs',
            items: {
              type: 'object',
              properties: {
                field: { type: 'string', description: 'Filter field name (e.g. "name", "state")' },
                value: { type: 'string', description: 'Filter value' },
              },
              required: ['field', 'value'],
            },
          },
          limit: { type: 'number', description: 'Max results to return (default 25)' },
          offset: { type: 'number', description: 'Number of results to skip (default 0)' },
        },
      },
      async (args: Record<string, unknown>) => {
        const filters = (args.filters as Array<{ field: string; value: string }>) ?? []
        const limit = (args.limit as number) ?? 25
        const offset = (args.offset as number) ?? 0
        const data = await gqlFetch(SEARCH_QUERY, {
          filters: filters.map((f) => ({ field: f.field, value: f.value })),
          limit,
          offset,
        })
        return JSON.stringify(data.search)
      },
    )

    mcp.registerTool(
      'get_search_fields',
      'Get available search field descriptors including field names, types, and options for choice fields.',
      { type: 'object', properties: {} },
      async () => {
        const data = await gqlFetch(SEARCH_FIELDS_QUERY)
        return JSON.stringify(data.searchFields)
      },
    )
  }, [])
}

package mcp

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5"
	"github.com/modelcontextprotocol/go-sdk/mcp"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/db"
	"github.com/ketang/kapow/api/internal/search"
)

// registerTools adds all Kapow MCP tools to the server.
func registerTools(srv *mcp.Server, deps *Deps) {
	mcp.AddTool(srv, &mcp.Tool{
		Name:        "search_colleges",
		Description: "Search for colleges and universities using filters. Returns matching institutions with name, city, state, and coordinates. Use get_search_fields to discover available filter fields and their accepted values.",
	}, makeSearchHandler(deps.DB, deps.Registry))

	mcp.AddTool(srv, &mcp.Tool{
		Name:        "get_search_fields",
		Description: "List all available search filter fields with their types, options, and metadata. Use this to discover what filters can be passed to search_colleges.",
	}, makeFieldsHandler(deps.Registry))

	mcp.AddTool(srv, &mcp.Tool{
		Name:        "get_college_detail",
		Description: "Look up detailed information for a single institution by its NCES unit ID. Returns the full denormalized data record including NCES statistics, rankings, weather, and more.",
	}, makeDetailHandler(deps.DB))
}

// searchInput is the typed input for the search_colleges tool.
type searchInput struct {
	Filters []search.FilterInput `json:"filters"`
	Limit   int                  `json:"limit,omitempty"`
	Offset  int                  `json:"offset,omitempty"`
}

func makeSearchHandler(db db.Querier, registry *search.Registry) func(context.Context, *mcp.CallToolRequest, searchInput) (*mcp.CallToolResult, any, error) {
	return func(ctx context.Context, _ *mcp.CallToolRequest, in searchInput) (*mcp.CallToolResult, any, error) {
		start := time.Now()
		filterNames := make([]string, 0, len(in.Filters))
		for _, f := range in.Filters {
			filterNames = append(filterNames, f.Field)
		}

		slog.Debug("mcp: search_colleges invoked",
			"filter_count", len(in.Filters),
			"filter_fields", filterNames,
			"limit", in.Limit,
			"offset", in.Offset,
		)

		req := search.SearchRequest{
			Filters: in.Filters,
			Limit:   in.Limit,
			Offset:  in.Offset,
		}

		// Validate the request before executing queries.
		authenticated := auth.GetClaims(ctx) != nil
		if errs := search.ValidateRequest(registry, req, authenticated); len(errs) > 0 {
			slog.Warn("mcp: search_colleges validation failed",
				"error_count", len(errs),
				"filter_fields", filterNames,
			)
			data, _ := json.Marshal(map[string]any{"errors": errs})
			return &mcp.CallToolResult{
				Content: []mcp.Content{
					&mcp.TextContent{Text: string(data)},
				},
				IsError: true,
			}, nil, nil
		}

		// Count total matching rows.
		countSQL, countArgs, err := search.BuildCountQuery(registry, req)
		if err != nil {
			slog.Error("mcp: search_colleges build count query failed", "error", err)
			return nil, nil, fmt.Errorf("mcp: build count query: %w", err)
		}
		var total int
		if err := db.QueryRow(ctx, countSQL, countArgs...).Scan(&total); err != nil {
			slog.Error("mcp: search_colleges count query failed", "error", err)
			return nil, nil, fmt.Errorf("mcp: count query: %w", err)
		}

		// Fetch paginated results.
		rowsSQL, rowsArgs, err := search.BuildQuery(registry, req)
		if err != nil {
			slog.Error("mcp: search_colleges build query failed", "error", err)
			return nil, nil, fmt.Errorf("mcp: build query: %w", err)
		}
		rows, err := db.Query(ctx, rowsSQL, rowsArgs...)
		if err != nil {
			slog.Error("mcp: search_colleges query failed", "error", err)
			return nil, nil, fmt.Errorf("mcp: query: %w", err)
		}
		defer rows.Close()

		var results []search.SearchResult
		for rows.Next() {
			var r search.SearchResult
			var rawData map[string]any // column 9: data blob (unused)
			if err := rows.Scan(&r.UnitID, &r.InstitutionName, &r.City, &r.State, &r.Latitude, &r.Longitude, &r.Distance, &r.MyPrice, &rawData, &r.BlendScore); err != nil {
				slog.Error("mcp: search_colleges scan failed", "error", err)
				return nil, nil, fmt.Errorf("mcp: scan: %w", err)
			}
			results = append(results, r)
		}
		if err := rows.Err(); err != nil {
			slog.Error("mcp: search_colleges rows error", "error", err)
			return nil, nil, fmt.Errorf("mcp: rows: %w", err)
		}

		effectiveLimit := search.DefaultLimit
		if in.Limit > 0 {
			effectiveLimit = in.Limit
		}

		resp := search.SearchResponse{
			Results: results,
			Total:   total,
			Limit:   effectiveLimit,
			Offset:  in.Offset,
		}

		data, err := json.Marshal(resp)
		if err != nil {
			return nil, nil, fmt.Errorf("mcp: marshal response: %w", err)
		}

		slog.Debug("mcp: search_colleges completed",
			"total_results", total,
			"returned_results", len(results),
			"duration_ms", time.Since(start).Milliseconds(),
		)

		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: string(data)},
			},
		}, nil, nil
	}
}

// fieldsInput is the typed input for get_search_fields (no parameters needed).
type fieldsInput struct{}

func makeFieldsHandler(registry *search.Registry) func(context.Context, *mcp.CallToolRequest, fieldsInput) (*mcp.CallToolResult, any, error) {
	return func(_ context.Context, _ *mcp.CallToolRequest, _ fieldsInput) (*mcp.CallToolResult, any, error) {
		descriptors := registry.Descriptors()
		data, err := json.Marshal(descriptors)
		if err != nil {
			return nil, nil, fmt.Errorf("mcp: marshal descriptors: %w", err)
		}
		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: string(data)},
			},
		}, nil, nil
	}
}

// detailInput is the typed input for get_college_detail.
type detailInput struct {
	UnitID string `json:"unit_id"`
}

func makeDetailHandler(db db.Querier) func(context.Context, *mcp.CallToolRequest, detailInput) (*mcp.CallToolResult, any, error) {
	return func(ctx context.Context, _ *mcp.CallToolRequest, in detailInput) (*mcp.CallToolResult, any, error) {
		start := time.Now()

		slog.Debug("mcp: get_college_detail invoked", "unit_id", in.UnitID)

		if in.UnitID == "" {
			slog.Warn("mcp: get_college_detail called with empty unit_id")
			return &mcp.CallToolResult{
				Content: []mcp.Content{
					&mcp.TextContent{Text: `{"error":"unit_id is required"}`},
				},
				IsError: true,
			}, nil, nil
		}

		const q = `SELECT unit_id, institution_name, city, state, latitude, longitude, data
			FROM search_base.dataset_merged WHERE unit_id = $1`

		var (
			unitID, name, city, state string
			lat, lng                  *float64
			data                      json.RawMessage
		)
		err := db.QueryRow(ctx, q, in.UnitID).Scan(&unitID, &name, &city, &state, &lat, &lng, &data)
		if err != nil {
			if errors.Is(err, pgx.ErrNoRows) {
				slog.Debug("mcp: get_college_detail institution not found",
					"unit_id", in.UnitID,
					"duration_ms", time.Since(start).Milliseconds(),
				)
				return &mcp.CallToolResult{
					Content: []mcp.Content{
						&mcp.TextContent{Text: fmt.Sprintf(`{"error":"institution not found","unit_id":%q}`, in.UnitID)},
					},
					IsError: true,
				}, nil, nil
			}
			slog.Error("mcp: get_college_detail query failed",
				"unit_id", in.UnitID,
				"error", err,
			)
			return nil, nil, fmt.Errorf("mcp: detail query: %w", err)
		}

		result := map[string]any{
			"unit_id":          unitID,
			"institution_name": name,
			"city":             city,
			"state":            state,
			"latitude":         lat,
			"longitude":        lng,
			"data":             data,
		}

		out, err := json.Marshal(result)
		if err != nil {
			return nil, nil, fmt.Errorf("mcp: marshal detail: %w", err)
		}

		slog.Debug("mcp: get_college_detail completed",
			"unit_id", in.UnitID,
			"duration_ms", time.Since(start).Milliseconds(),
		)

		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: string(out)},
			},
		}, nil, nil
	}
}

