package mcp

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"testing"

	"github.com/modelcontextprotocol/go-sdk/mcp"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/search"
)

// TestContractMatrix_MCP runs the shared contract cases through the MCP
// search handler, verifying that the MCP adapter produces the same
// validation outcomes as the baseline.
func TestContractMatrix_MCP(t *testing.T) {
	t.Parallel()
	defaultReg := search.NewRegistry()

	for _, cc := range search.ContractCases() {
		if cc.SkipMCP {
			continue
		}

		t.Run(cc.Name, func(t *testing.T) {
			t.Parallel()

			reg := defaultReg
			if cc.Registry != nil {
				reg = cc.Registry
			}

			handler := makeSearchHandler(nil, reg)

			in := searchInput{
				Filters: cc.Request.Filters,
				Limit:   cc.Request.Limit,
				Offset:  cc.Request.Offset,
			}

			ctx := context.Background()
			if cc.Authenticated {
				ctx = auth.SetClaims(ctx, &auth.Claims{})
			}

			if cc.WantValid {
				// Validation passes â†’ handler proceeds to DB call â†’ nil Querier panics.
				// Run in a goroutine to isolate the panic from testing.T's recovery.
				panicked := make(chan bool, 1)
				errCh := make(chan error, 1)
				go func() {
					defer func() {
						if r := recover(); r != nil {
							panicked <- true
						} else {
							panicked <- false
						}
					}()
					result, _, err := handler(ctx, nil, in)
					if err != nil {
						errCh <- err
						return
					}
					if result.IsError {
						errCh <- fmt.Errorf("expected valid request, got IsError with: %v", result.Content)
						return
					}
					errCh <- nil
				}()

				select {
				case p := <-panicked:
					if !p {
						t.Fatal("expected panic from nil DB (validation should have passed)")
					}
					// Panic from nil Querier = validation passed âœ“
				case err := <-errCh:
					if err != nil {
						t.Fatal(err)
					}
					// No panic and no error means it somehow succeeded (shouldn't happen with nil DB)
				}
				return
			}

			// Expect validation failure â†’ IsError=true.
			result, _, err := handler(ctx, nil, in)
			if err != nil {
				t.Fatalf("unexpected Go error: %v", err)
			}
			if !result.IsError {
				t.Fatal("expected IsError=true for invalid request")
			}

			text, ok := result.Content[0].(*mcp.TextContent)
			if !ok {
				t.Fatalf("expected TextContent, got %T", result.Content[0])
			}

			var body struct {
				Errors []struct {
					Field   string `json:"field"`
					Message string `json:"message"`
				} `json:"errors"`
			}
			if err := json.Unmarshal([]byte(text.Text), &body); err != nil {
				t.Fatalf("decode error response: %v", err)
			}
			if len(body.Errors) == 0 {
				t.Fatal("expected validation errors in response")
			}

			found := false
			for _, e := range body.Errors {
				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
					found = true
					break
				}
			}
			if !found {
				t.Errorf("expected error field=%q containing %q, got: %+v",
					cc.WantField, cc.WantContains, body.Errors)
			}
		})
	}
}

package search

// ExactNumericFilter matches rows where the field equals Value.
type ExactNumericFilter struct {
	Value float64 `json:"value"`
}

// NumericRangeFilter matches rows where the field is within [Min, Max].
// At least one of Min or Max must be non-nil.
type NumericRangeFilter struct {
	Min *float64 `json:"min,omitempty"`
	Max *float64 `json:"max,omitempty"`
}

// SubstringFilter performs a case-insensitive substring match.
type SubstringFilter struct {
	Value string `json:"value"`
}

// FullTextFilter performs a full-text search using plainto_tsquery.
type FullTextFilter struct {
	Query string `json:"query"`
}

// ExactStringFilter matches rows where the field equals Value (case-sensitive or not
// depending on the field definition).
type ExactStringFilter struct {
	Value string `json:"value"`
}

// SingleEnumFilter matches rows where the field equals one specific enum value.
type SingleEnumFilter struct {
	Value string `json:"value"`
}

// MultiEnumFilter matches rows where the field contains any/all of the given values.
type MultiEnumFilter struct {
	Values []string `json:"values"`
}

// GeoFilterKind discriminates between radius and bounding-box geo filters.
type GeoFilterKind string

const (
	GeoFilterKindRadius GeoFilterKind = "radius"
	GeoFilterKindBBox   GeoFilterKind = "bbox"
)

// GeoRadiusFilter specifies a centre point and search radius.
type GeoRadiusFilter struct {
	Lat      float64 `json:"lat"`
	Lng      float64 `json:"lng"`
	RadiusKm float64 `json:"radius_km"`
}

// GeoBoundingBoxFilter specifies an axis-aligned geographic bounding box.
type GeoBoundingBoxFilter struct {
	MinLat float64 `json:"min_lat"`
	MaxLat float64 `json:"max_lat"`
	MinLng float64 `json:"min_lng"`
	MaxLng float64 `json:"max_lng"`
}

// GeoFilterInput is the top-level geo filter that wraps the specific kind.
type GeoFilterInput struct {
	Kind   GeoFilterKind        `json:"kind"`
	Radius *GeoRadiusFilter     `json:"radius,omitempty"`
	BBox   *GeoBoundingBoxFilter `json:"bbox,omitempty"`
}

