	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/modelcontextprotocol/go-sdk/mcp"
	"github.com/pashagolub/pgxmock/v4"

	"github.com/ketang/kapow/api/internal/search"
)

// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Unit tests â€” no DB required
// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

func TestGetSearchFields(t *testing.T) {
	t.Parallel()
	registry := search.NewRegistry()
	handler := makeFieldsHandler(registry)

	result, _, err := handler(context.Background(), nil, fieldsInput{})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result == nil {
		t.Fatal("result is nil")
	}
	if len(result.Content) == 0 {
		t.Fatal("result has no content")
	}

	text, ok := result.Content[0].(*mcp.TextContent)
	if !ok {
		t.Fatalf("expected TextContent, got %T", result.Content[0])
	}

	var descriptors []search.FieldDescriptor
	if err := json.Unmarshal([]byte(text.Text), &descriptors); err != nil {
		t.Fatalf("failed to unmarshal descriptors: %v", err)
	}
	if len(descriptors) == 0 {
		t.Error("expected non-empty descriptors list")
	}

	// Verify that key fields are present.
	names := make(map[string]bool)
	for _, d := range descriptors {
		names[d.Name] = true
	}
	for _, want := range []string{"name", "state", "enrollment"} {
		if !names[want] {
			t.Errorf("expected field %q in descriptors", want)
		}
	}
}

func TestGetCollegeDetail_EmptyUnitID(t *testing.T) {
	t.Parallel()
	handler := makeDetailHandler(nil)

	result, _, err := handler(context.Background(), nil, detailInput{UnitID: ""})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !result.IsError {
		t.Error("expected IsError=true for empty unit_id")
	}

	text, ok := result.Content[0].(*mcp.TextContent)
	if !ok {
		t.Fatalf("expected TextContent, got %T", result.Content[0])
	}
	if !strings.Contains(text.Text, "unit_id is required") {
		t.Errorf("expected error about unit_id, got: %s", text.Text)
	}
}

func TestSearchInput_Defaults(t *testing.T) {
	t.Parallel()
	// Verify that searchInput correctly serializes/deserializes.
	raw := `{"filters":[{"field":"state","value":"\"CA\""}],"limit":5}`
	var in searchInput
	if err := json.Unmarshal([]byte(raw), &in); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if len(in.Filters) != 1 {
		t.Errorf("expected 1 filter, got %d", len(in.Filters))
	}
	if in.Filters[0].Field != "state" {
		t.Errorf("expected field=state, got %q", in.Filters[0].Field)
	}
	if in.Limit != 5 {
		t.Errorf("expected limit=5, got %d", in.Limit)
	}
	if in.Offset != 0 {
		t.Errorf("expected offset=0, got %d", in.Offset)
	}
}

// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Validation tests â€” no DB required (validation runs before any query)
// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

func TestSearchHandler_UnknownField(t *testing.T) {
	t.Parallel()
	registry := search.NewRegistry()
	handler := makeSearchHandler(nil, registry)

	result, _, err := handler(context.Background(), nil, searchInput{
		Filters: []search.FilterInput{
			{Field: "does_not_exist", Value: json.RawMessage(`"x"`)},
		},
	})
	if err != nil {
		t.Fatalf("unexpected Go error: %v", err)
	}
	if !result.IsError {
		t.Fatal("expected IsError=true for unknown field")
	}

	text := result.Content[0].(*mcp.TextContent)
	if !strings.Contains(text.Text, "unknown field") {
		t.Errorf("expected 'unknown field' in error, got: %s", text.Text)
	}
}

func TestSearchHandler_InvalidEnumValue(t *testing.T) {
	t.Parallel()
	registry := search.NewRegistry()
	handler := makeSearchHandler(nil, registry)

	result, _, err := handler(context.Background(), nil, searchInput{
		Filters: []search.FilterInput{
			{Field: "state", Value: json.RawMessage(`{"values":["XX"]}`)},
		},
	})
	if err != nil {
		t.Fatalf("unexpected Go error: %v", err)
	}
	if !result.IsError {
		t.Fatal("expected IsError=true for invalid enum value")
	}

	text := result.Content[0].(*mcp.TextContent)
	if !strings.Contains(text.Text, "not in allowed options") {
		t.Errorf("expected 'not in allowed options' in error, got: %s", text.Text)
	}
}

func TestSearchHandler_LimitExceedsMax(t *testing.T) {
	t.Parallel()
	registry := search.NewRegistry()
	handler := makeSearchHandler(nil, registry)

	result, _, err := handler(context.Background(), nil, searchInput{
		Limit: 200,
	})
	if err != nil {
		t.Fatalf("unexpected Go error: %v", err)
	}
	if !result.IsError {
		t.Fatal("expected IsError=true for limit exceeding max")
	}

	text := result.Content[0].(*mcp.TextContent)
	if !strings.Contains(text.Text, "limit exceeds maximum") {
		t.Errorf("expected 'limit exceeds maximum' in error, got: %s", text.Text)
	}
}

// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Mock-based unit tests â€” pgxmock replaces the real database
// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

func ptrFloat64(f float64) *float64 { return &f }

func TestSearchHandler_NoFilters_Mock(t *testing.T) {
	t.Parallel()
	mock, err := pgxmock.NewPool()
	if err != nil {
		t.Fatalf("pgxmock.NewPool: %v", err)
	}
	defer mock.Close()

	mock.ExpectQuery("SELECT COUNT").
		WillReturnRows(pgxmock.NewRows([]string{"count"}).AddRow(2))

	mock.ExpectQuery("SELECT unit_id").
		WithArgs(search.DefaultLimit, 0).
		WillReturnRows(pgxmock.NewRows([]string{
			"unit_id", "institution_name", "city", "state", "latitude", "longitude",
			"distance", "my_price", "data", "blend_score",
		}).
			AddRow("100001", "University A", "Boston", "MA", ptrFloat64(42.0), ptrFloat64(-71.0), nil, nil, map[string]any{}, nil).
			AddRow("100002", "College B", "NYC", "NY", ptrFloat64(40.7), ptrFloat64(-74.0), nil, nil, map[string]any{}, nil))

	registry := search.NewRegistry()
	handler := makeSearchHandler(mock, registry)

	result, _, err := handler(context.Background(), nil, searchInput{})
	if err != nil {
		t.Fatalf("search: %v", err)
	}

	text := result.Content[0].(*mcp.TextContent)
	var resp search.SearchResponse
	if err := json.Unmarshal([]byte(text.Text), &resp); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if resp.Total != 2 {
		t.Errorf("Total = %d, want 2", resp.Total)
	}
	if len(resp.Results) != 2 {
		t.Errorf("len(Results) = %d, want 2", len(resp.Results))
	}
	if resp.Limit != search.DefaultLimit {
		t.Errorf("Limit = %d, want %d", resp.Limit, search.DefaultLimit)
	}

	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

func TestSearchHandler_WithLimit_Mock(t *testing.T) {
	t.Parallel()
	mock, err := pgxmock.NewPool()
	if err != nil {
		t.Fatalf("pgxmock.NewPool: %v", err)
	}
	defer mock.Close()

	mock.ExpectQuery("SELECT COUNT").
		WillReturnRows(pgxmock.NewRows([]string{"count"}).AddRow(50))

	mock.ExpectQuery("SELECT unit_id").
		WithArgs(5, 10).
		WillReturnRows(pgxmock.NewRows([]string{
			"unit_id", "institution_name", "city", "state", "latitude", "longitude",
			"distance", "my_price", "data", "blend_score",
		}).
			AddRow("300001", "Uni X", "LA", "CA", ptrFloat64(34.0), ptrFloat64(-118.0), nil, nil, map[string]any{}, nil))

	registry := search.NewRegistry()
	handler := makeSearchHandler(mock, registry)

	result, _, err := handler(context.Background(), nil, searchInput{Limit: 5, Offset: 10})
	if err != nil {
		t.Fatalf("search: %v", err)
	}

	text := result.Content[0].(*mcp.TextContent)
	var resp search.SearchResponse
	if err := json.Unmarshal([]byte(text.Text), &resp); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if resp.Limit != 5 {
		t.Errorf("Limit = %d, want 5", resp.Limit)
	}
	if resp.Offset != 10 {
		t.Errorf("Offset = %d, want 10", resp.Offset)
	}

	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

func TestSearchHandler_CountQueryError(t *testing.T) {
	t.Parallel()
